import{_ as n,H as i,f as r,i as a}from"./chunks/framework.DbTCwA-u.js";const c=JSON.parse('{"title":"Fehlerbehebung","description":"Häufige Probleme und Lösungen bei der Verwendung von EligiusNametag.","frontmatter":{"title":"Fehlerbehebung","description":"Häufige Probleme und Lösungen bei der Verwendung von EligiusNametag."},"headers":[],"relativePath":"de/troubleshooting.md","filePath":"de/troubleshooting.md"}'),t={name:"de/troubleshooting.md"};function o(l,e,s,d,u,h){return i(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="fehlerbehebung-troubleshooting" tabindex="-1">Fehlerbehebung (Troubleshooting) <a class="header-anchor" href="#fehlerbehebung-troubleshooting" aria-label="Permalink to &quot;Fehlerbehebung (Troubleshooting)&quot;">​</a></h1><p>Haben Sie Probleme mit EligiusNametag? Überprüfen Sie diese häufigen Lösungen:</p><h3 id="_1-das-nametag-erscheint-nicht-uber-dem-spieler" tabindex="-1">1. Das Nametag erscheint nicht über dem Spieler <a class="header-anchor" href="#_1-das-nametag-erscheint-nicht-uber-dem-spieler" aria-label="Permalink to &quot;1. Das Nametag erscheint nicht über dem Spieler&quot;">​</a></h3><ul><li><strong>Haben Sie ProtocolLib installiert?</strong> Unser Plugin ist strikt auf Paketinjektion angewiesen, damit Nametags reibungslos schweben, ohne Lags zu verursachen.</li><li><strong>Haben Sie PlaceholderAPI installiert?</strong> Wenn Sie Variablen wie <code>%vault_rank%</code> verwenden und keine PAPI haben, kann der Text möglicherweise nicht gerendert werden.</li></ul><h3 id="_2-database-connection-closed-fehler" tabindex="-1">2. &quot;Database Connection Closed&quot; Fehler <a class="header-anchor" href="#_2-database-connection-closed-fehler" aria-label="Permalink to &quot;2. &quot;Database Connection Closed&quot; Fehler&quot;">​</a></h3><ul><li>Dies wurde in den <strong>neuesten Versionen behoben</strong>. Stellen Sie sicher, dass Sie die neueste Version <code>v1.x.x</code> oder höher verwenden. Wenn Sie <strong>MySQL</strong> verwenden, überprüfen Sie, ob die IP und die Anmeldeinformationen in der <code>config.yml</code> korrekt sind. Verwenden Sie andernfalls lokales <code>SQLITE</code>.</li></ul><h3 id="_3-viaversion-warnungen-in-der-konsole" tabindex="-1">3. ViaVersion-Warnungen in der Konsole <a class="header-anchor" href="#_3-viaversion-warnungen-in-der-konsole" aria-label="Permalink to &quot;3. ViaVersion-Warnungen in der Konsole&quot;">​</a></h3><p>Wenn Sie ViaVersion verwenden, um Spielern auf 1.20 den Beitritt zu Ihrem 1.21+ Server zu ermöglichen, sehen Sie möglicherweise Meldungen über <em>Metadata</em> und <em>Protocol Versions</em>.</p><ul><li><strong>Ursache:</strong> Dem alten Client (z. B. 1.20.2) fehlt der native Code, um große <code>TEXT_DISPLAY</code> Einheiten richtig zu verarbeiten.</li><li><strong>Lösung:</strong> Wir empfehlen dringend, 1.21+ Versionen für die perfekte Hologramm-Visualisierung vorauszusetzen, oder ignorieren Sie einfach die Warnung, wenn beim Spieler keine visuellen Abstürze auftreten.</li></ul><h3 id="_4-enametag-lang-aktualisiert-die-hilfemeldung-nicht" tabindex="-1">4. /enametag lang aktualisiert die Hilfemeldung nicht <a class="header-anchor" href="#_4-enametag-lang-aktualisiert-die-hilfemeldung-nicht" aria-label="Permalink to &quot;4. /enametag lang aktualisiert die Hilfemeldung nicht&quot;">​</a></h3><p>Wenn Sie <code>/enametag lang de</code> verwenden, liest das Plugin aus <code>lang/de.yml</code>. Wenn Sie bemerken, dass eine Übersetzung leer ist oder sich ein Befehl seltsam verhält, können Sie den <code>lang/</code> Ordner in Ihrem Plugin-Verzeichnis löschen, damit EligiusNametag ihn mit den neuesten Standards sauber neu generieren kann.</p>',11)])])}const m=n(t,[["render",o]]);export{c as __pageData,m as default};
